from matplotlib import pyplot as pltimport numpy as npimport cv2from skimage import io, img_as_floatfrom skimage.restoration import denoise_nl_means, estimate_sigmaimg = img_as_float(io.imread("../data/BSE_25sigma_noisy.jpg", 0))sigma_est = np.mean(estimate_sigma(img))print(sigma_est)denoise_img = denoise_nl_means(img, h = 1.*sigma_est, fast_mode = True, patch_size = 3,                               patch_distance = 5)plt.figure()plt.imshow(denoise_img, cmap  = "grey")plt.title("NLM denoise")"""sigma_estEstimated noise level in the image.Higher values indicate more noise.Often used to automatically scale the denoising strength.h Controls denoising intensity.Small → preserves detailsLarge → stronger smoothingpatch_sizeDefines the local patch dimensions.Larger patches capture more structure but increase computation.patch_distanceDefines how far the algorithm searches for similar patches.Larger values improve denoising but increase runtime."""